    with open(cases_result, 'r') as f:
        cases = json.load(f)
else:
    cases = cases_result

cutoff = datetime(2022, 8, 16)
counts = {}

for case in cases:
    dt_part = case['createddate'].split('T')[0]
    case_date = datetime.strptime(dt_part, '%Y-%m-%d')
